import { writable } from 'svelte/store';

function createCandidates() {
	const candidates = writable({});

	return {
		subscribe: candidates.subscribe,
		// 增加 set 方法，让领域层可以覆盖其状态
		set: candidates.set, 

		// 保留 add/clear 供 Keyboard.svelte 暂时使用，但内部逻辑会逐渐被同步覆盖
		add(pos, candidate) {
			candidates.update($candidates => {
				const key = pos.x + ',' + pos.y;
				if (!$candidates[key]) {
					$candidates[key] = [candidate];
				} else if ($candidates[key].includes(candidate)) {
					$candidates[key] = $candidates[key].filter(v => v !== candidate);
				} else {
					$candidates[key] = [...$candidates[key], candidate].sort((a, b) => a - b);
				}
				return $candidates;
			});
		},

		clear(pos) {
			candidates.update($candidates => {
				delete $candidates[pos.x + ',' + pos.y];
				return $candidates;
			});
		}
	}
}

export const candidates = createCandidates();